        if r['resume_id'] == resume_id:
            return r
    return None

# Helper to find max id in a list of dicts with 'id' field
# id_field is the field name string

def get_next_id(items, id_field):
    if not items:
        return 1
    try:
        return max(item[id_field] for item in items) + 1
    except Exception:
        return 1


