@app.route('/dashboard')
def dashboard_page():
    # featured_jobs: Let's treat featured_jobs as the first 5 jobs by posted_date descending
    jobs = read_jobs()
    # sort by posted_date desc
    jobs_sorted = sorted(jobs, key=lambda j: j['posted_date'], reverse=True)
    featured_jobs = []
