@app.route('/dashboard')
def dashboard_page():
    # featured_jobs: Let's treat featured_jobs as the first 5 jobs by posted_date descending
    jobs = read_jobs()
    # sort by posted_date desc
    jobs_sorted = sorted(jobs, key=lambda j: j['posted_date'], reverse=True)
    featured_jobs = []
    count = 0
    for job in jobs_sorted:
        if count >= 5:
            break
        company = get_company_by_id(job['company_id'])
        if not company:
            continue
        featured_jobs.append({
            'job_id': job['job_id'],
