@app.route('/jobs', methods=['GET', 'POST'])
def job_listings_page():
    jobs = read_jobs()
    categories = get_category_names()  # list of category names
    locations = get_job_locations()

    search_query = None
    selected_category = None
    selected_location = None

    if request.method == 'POST':
        search_query = request.form.get('search_input', '').strip() or None
        selected_category = request.form.get('category_filter', '').strip() or None
        selected_location = request.form.get('location_filter', '').strip() or None
    else:
        # GET - get parameters from query args if any
        search_query = None
        selected_category = None
        selected_location = None

    # Filter jobs
    filtered_jobs = []
    for job in jobs:
        # filter by category
        if selected_category and job['category'] != selected_category:
            continue
        # filter by location
        if selected_location and job['location'] != selected_location:
            continue
        # filter by search_query - in title, company name, or location
        company = get_company_by_id(job['company_id'])
        if company is None:
            continue
        if search_query:
            sq_lower = search_query.lower()
            if (sq_lower not in job['title'].lower() and
                    sq_lower not in company['company_name'].lower() and
                    sq_lower not in job['location'].lower()):
                continue

        filtered_jobs.append({
            'job_id': job['job_id'],
            'title': job['title'],
            'company_name': company['company_name'],
            'location': job['location'],
            'salary_min': job['salary_min'],
            'salary_max': job['salary_max'],
        })

    return render_template('jobs.html',
                           jobs=filtered_jobs,
                           categories=categories,
                           locations=locations,
                           selected_category=selected_category,
                           selected_location=selected_location,
                           search_query=search_query)

