@app.route('/job/<int:job_id>/apply', methods=['GET', 'POST'])
def application_form_page(job_id):
    job = get_job_by_id(job_id)
    if not job:
        return "Job not found", 404
    company = get_company_by_id(job['company_id'])
    company_name = company['company_name'] if company else 'Unknown'
    job_data = {
        'job_id': job['job_id'],
        'title': job['title'],
        'company_name': company_name
    }

    if request.method == 'GET':
        return render_template('application_form.html', job=job_data)
    else:
        # POST - submit_application
        applicant_name = request.form.get('applicant_name', '').strip()
        applicant_email = request.form.get('applicant_email', '').strip()
        cover_letter = request.form.get('cover_letter', '').strip()
        resume_file = request.files.get('resume_upload')

        form_errors = {}

        # Validate inputs
        if not applicant_name:
            form_errors['applicant_name'] = 'Applicant name is required.'
        if not applicant_email:
            form_errors['applicant_email'] = 'Applicant email is required.'
        elif '@' not in applicant_email or '.' not in applicant_email:
            form_errors['applicant_email'] = 'Invalid email address.'
        if not cover_letter:
            form_errors['cover_letter'] = 'Cover letter is required.'
        if not resume_file or resume_file.filename == '':
            form_errors['resume_upload'] = 'Resume file is required.'

        if form_errors:
            return render_template('application_form.html', job=job_data, form_errors=form_errors)

        # Save the resume file
        resumes = read_resumes()
        new_resume_id = get_next_id(resumes, 'resume_id')

        # Save resume file to data/resumes/ directory
        resumes_dir = os.path.join(DATA_DIR, 'resumes')
        if not os.path.exists(resumes_dir):
            os.makedirs(resumes_dir)

        filename = resume_file.filename
        # Make filename safe by just using basename
        filename = os.path.basename(filename)

        # To avoid overwrite, prepend new_resume_id and timestamp
        timestamp = datetime.utcnow().strftime('%Y%m%d%H%M%S')
        saved_filename = f"{new_resume_id}_{timestamp}_{filename}"
        save_path = os.path.join(resumes_dir, saved_filename)
        resume_file.save(save_path)

        upload_date = datetime.utcnow().strftime('%Y-%m-%d')
        new_resume = {
            'resume_id': new_resume_id,
            'applicant_name': applicant_name,
            'applicant_email': applicant_email,
            'filename': saved_filename,
            'upload_date': upload_date,
            'summary': ''  # no summary from job application form
        }

        resumes.append(new_resume)
        save_resumes(resumes)

        # Create new application
        applications = read_applications()
        new_application_id = get_next_id(applications, 'application_id')
        new_application = {
            'application_id': new_application_id,
            'job_id': job['job_id'],
            'applicant_name': applicant_name,
            'applicant_email': applicant_email,
            'status': 'Applied',
            'applied_date': upload_date,
            'resume_id': new_resume_id
        }
        applications.append(new_application)
        save_applications(applications)

        # Redirect to application tracking page after submission
        return redirect(url_for('application_tracking_page'))


