from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Data reading and writing functions for each data file

def read_jobs():
    path = os.path.join(DATA_DIR, 'jobs.txt')
    jobs = []
    if not os.path.isfile(path):
        return jobs
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 9:
                continue
            try:
                jobs.append({
                    'job_id': int(parts[0]),
                    'title': parts[1],
                    'company_id': int(parts[2]),
                    'location': parts[3],
                    'salary_min': int(parts[4]),
                    'salary_max': int(parts[5]),
                    'category': parts[6],
                    'description': parts[7],
                    'posted_date': parts[8]
                })
            except Exception:
                continue
    return jobs

def save_jobs(jobs):
    path = os.path.join(DATA_DIR, 'jobs.txt')
