# Helper to get next id given a list of dicts and id field

def get_next_id(items, id_field):
    if not items:
        return 1
    try:
        return max(item[id_field] for item in items) + 1
    except Exception:
        return 1

# Helpers to get entities by id

def get_job_by_id(job_id):
    jobs = read_jobs()
    for job in jobs:
        if job['job_id'] == job_id:
            return job
    return None

def get_company_by_id(company_id):
    companies = read_companies()
    for c in companies:
        if c['company_id'] == company_id:
            return c
    return None

def get_application_by_id(application_id):
    apps = read_applications()
    for a in apps:
        if a['application_id'] == application_id:
            return a
    return None

def get_resume_by_id(resume_id):
    resumes = read_resumes()
    for r in resumes:
        if r['resume_id'] == resume_id:
            return r
    return None

# Helper to get category names

def get_category_names():
    return [cat['category_name'] for cat in read_categories()]

# Helper to get unique locations from jobs

def get_job_locations():
    locs = set()
    for job in read_jobs():
        locs.add(job['location'])
    return sorted(locs)

