            try:
                applications.append({
                    'application_id': int(parts[0]),
                    'job_id': int(parts[1]),
                    'applicant_name': parts[2],
                    'applicant_email': parts[3],
                    'status': parts[4],
                    'applied_date': parts[5],
                    'resume_id': int(parts[6])
                })
            except Exception:
                continue
    return applications

def save_applications(applications):
    path = os.path.join(DATA_DIR, 'applications.txt')
    with open(path, "w", encoding="utf-8") as f:
        for a in applications:
            line = f"{a['application_id']}|{a['job_id']}|{a['applicant_name']}|{a['applicant_email']}|{a['status']}|{a['applied_date']}|{a['resume_id']}"
            f.write(line + "\n")

def read_resumes():
    path = os.path.join(DATA_DIR, 'resumes.txt')
    resumes = []
    if not os.path.isfile(path):
        return resumes
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line=line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < 6:
                continue
            try:
                resumes.append({
                    'resume_id': int(parts[0]),
                    'applicant_name': parts[1],
                    'applicant_email': parts[2],
                    'filename': parts[3],
                    'upload_date': parts[4],
                    'summary': parts[5]
                })
            except Exception:
                continue
    return resumes

def save_resumes(resumes):
    path = os.path.join(DATA_DIR, 'resumes.txt')
    with open(path, "w", encoding="utf-8") as f:
        for r in resumes:
            line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
            f.write(line + "\n")

# Helper to get next id given a list of dicts and id field

def get_next_id(items, id_field):
    if not items:
        return 1
    try:
        return max(item[id_field] for item in items) + 1
    except Exception:
        return 1

# Helpers to get entities by id

def get_job_by_id(job_id):
    jobs = read_jobs()
    for job in jobs:
        if job['job_id'] == job_id:
            return job
    return None

def get_company_by_id(company_id):
    companies = read_companies()
    for c in companies:
        if c['company_id'] == company_id:
            return c
    return None

def get_application_by_id(application_id):
    apps = read_applications()
    for a in apps:
        if a['application_id'] == application_id:
            return a
    return None

def get_resume_by_id(resume_id):
    resumes = read_resumes()
    for r in resumes:
        if r['resume_id'] == resume_id:
            return r
    return None

# Helper to get category names

def get_category_names():
    return [cat['category_name'] for cat in read_categories()]

# Helper to get unique locations from jobs

def get_job_locations():
    locs = set()
    for job in read_jobs():
        locs.add(job['location'])
    return sorted(locs)

